    public static class QueryReport
    {
        private readonly static string _connectionString = "<Your_Connection_String>";

        [Function(nameof(QueryReport))]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Anonymous, "get", Route = "reports")] HttpRequestData req)
